class Solution:
    def minimumCost(self, source: str, target: str, original: List[str], changed: List[str], cost: List[int]) -> int:
        from collections import defaultdict

        # Step 1: Build the graph
        graph = defaultdict(dict)
        for o, c, co in zip(original, changed, cost):
            if c not in graph[o] or graph[o][c] > co:
                graph[o][c] = co

        # Step 2: Initialize distance matrix
        chars = set(original + changed)
        m = len(chars)
        char_to_idx = {ch: i for i, ch in enumerate(chars)}
        INF = float('inf')
        dist = [[INF] * m for _ in range(m)]

        for i in range(m):
            dist[i][i] = 0

        for o, c, co in zip(original, changed, cost):
            u = char_to_idx[o]
            v = char_to_idx[c]
            dist[u][v] = min(dist[u][v], co)

        # Step 3: Floyd-Warshall algorithm
        for k in range(m):
            for i in range(m):
                for j in range(m):
                    if dist[i][k] + dist[k][j] < dist[i][j]:
                        dist[i][j] = dist[i][k] + dist[k][j]

        # Step 4: Calculate total cost
        total_cost = 0
        for s_char, t_char in zip(source, target):
            if s_char == t_char:
                continue
            if s_char not in char_to_idx or t_char not in char_to_idx:
                return -1
            u = char_to_idx[s_char]
            v = char_to_idx[t_char]
            if dist[u][v] == INF:
                return -1
            total_cost += dist[u][v]

        return total_cost
